{
  "name": "Setmandu Matrimonial",
  "description": "A premium, animated matrimonial platform for Nepali users featuring an intelligent match-scoring engine and a high-end glassmorphism design.",
  "requestFramePermissions": ["camera"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Gender = 'male' | 'female' | 'other';

export interface UserProfile {
  uid: string;
  fullName: string;
  gender: Gender;
  age: number;
  casteEthnicity: string;
  district: string;
  countryResidence: string;
  occupation: string;
  education: string;
  height: string;
  recentPhotoURL: string;
  preferredPartnerGender: Gender;
  preferredAgeRange: string;
  preferredCasteCommunity: string;
  preferredCountry: string;
  isVerified: boolean;
  registrationDate: string;
  bio?: string;
  // Private fields (not to be displayed)
  email?: string;
  phone?: string;
}

export interface MatchResult extends UserProfile {
  score: number;
}

import React, { useState, useEffect } from 'react';
import { UserProfile } from './types';
import Navigation from './components/Navigation';
import Hero from './components/Hero';
import RegistrationForm from './components/RegistrationForm';
import MatchingEngine from './components/MatchingEngine';
import BackgroundHearts from './components/BackgroundHearts';
import Stats from './components/Stats';
import Footer from './components/Footer';

enum AppState {
  HOME = 'home',
  REGISTER = 'register',
  MATCHING = 'matching'
}

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.HOME);
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);

  // Scroll to top on state change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [appState]);

  const handleRegistrationComplete = (userData: UserProfile) => {
    setCurrentUser(userData);
    setAppState(AppState.MATCHING);
  };

  return (
    <div className="relative min-h-screen">
      <BackgroundHearts />
      <Navigation onHome={() => setAppState(AppState.HOME)} onRegister={() => setAppState(AppState.REGISTER)} />

      <main className="relative z-10 pt-20">
        {appState === AppState.HOME && (
          <>
            <Hero onStart={() => setAppState(AppState.REGISTER)} />
            <Stats />
            <div className="max-w-6xl mx-auto px-6 py-20 text-center">
              <h2 className="text-3xl md:text-4xl font-bold mb-12 rose-gold-text">How It Works</h2>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <StepCard 
                  icon="📝" 
                  title="Create Profile" 
                  desc="Tell us about yourself, your family, and what you're looking for." 
                />
                <StepCard 
                  icon="💖" 
                  title="Smart Matching" 
                  desc="Our AI-powered scoring engine finds the most compatible partners." 
                />
                <StepCard 
                  icon="💍" 
                  title="Connect" 
                  desc="Start conversations and meet your future life partner." 
                />
              </div>
            </div>
          </>
        )}

        {appState === AppState.REGISTER && (
          <div className="max-w-4xl mx-auto px-6 py-10">
            <RegistrationForm onComplete={handleRegistrationComplete} />
          </div>
        )}

        {appState === AppState.MATCHING && currentUser && (
          <div className="max-w-6xl mx-auto px-6 py-10">
            <MatchingEngine currentUser={currentUser} />
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
};

const StepCard: React.FC<{icon: string, title: string, desc: string}> = ({ icon, title, desc }) => (
  <div className="glass p-8 rounded-2xl border border-white/10 hover:border-purple-500/50 transition-all">
    <div className="text-5xl mb-6">{icon}</div>
    <h3 className="text-xl font-bold mb-3">{title}</h3>
    <p className="text-gray-400 text-sm leading-relaxed">{desc}</p>
  </div>
);

export default App;

