import React, { useState } from 'react';
import { UserProfile, Gender } from '../types';

interface RegistrationFormProps {
  onComplete: (userData: UserProfile) => void;
}

const RegistrationForm: React.FC<RegistrationFormProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<Partial<UserProfile>>({
    gender: 'male',
    age: 25,
    countryResidence: 'Nepal',
    isVerified: true,
    registrationDate: new Date().toISOString(),
    preferredAgeRange: '20-30',
    preferredCountry: 'Any',
    preferredCasteCommunity: 'Any'
  });

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (step < 4) {
      nextStep();
    } else {
      // Final submission simulation
      const fullData: UserProfile = {
        ...(formData as UserProfile),
        uid: Math.random().toString(36).substring(7),
        recentPhotoURL: `https://picsum.photos/seed/${formData.fullName}/400/400`,
        isVerified: true
      };
      onComplete(fullData);
    }
  };

  const updateField = (field: keyof UserProfile, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="glass p-8 md:p-12 rounded-3xl shadow-2xl relative overflow-hidden">
      {/* Progress Bar */}
      <div className="absolute top-0 left-0 w-full h-1 bg-white/5">
        <div 
          className="h-full bg-purple-500 transition-all duration-500" 
          style={{ width: `${(step / 4) * 100}%` }}
        ></div>
      </div>

      <div className="mb-10 flex justify-between items-center">
        <h2 className="text-3xl font-bold rose-gold-text">Step {step} of 4</h2>
        <span className="text-gray-400 text-sm italic">Almost there...</span>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {step === 1 && (
          <div className="animate-fadeIn space-y-6">
            <h3 className="text-xl font-semibold mb-6">Personal Information (व्यक्तिगत जानकारी)</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm text-gray-400 mb-2">Full Name</label>
                <input 
                  required
                  type="text" 
                  value={formData.fullName || ''}
                  onChange={e => updateField('fullName', e.target.value)}
                  placeholder="Enter full name"
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Age</label>
                <input 
                  required
                  type="number" 
                  min="18"
                  max="70"
                  value={formData.age || 25}
                  onChange={e => updateField('age', parseInt(e.target.value))}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Gender</label>
                <select 
                  className="w-full bg-white/10 border border-white/10 rounded-xl px-4 py-3 outline-none"
                  value={formData.gender}
                  onChange={e => updateField('gender', e.target.value)}
                >
                  <option value="male" className="bg-[#0f071a]">Male</option>
                  <option value="female" className="bg-[#0f071a]">Female</option>
                </select>
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Height (e.g. 5'7")</label>
                <input 
                  required
                  type="text" 
                  value={formData.height || ''}
                  onChange={e => updateField('height', e.target.value)}
                  placeholder="5'8\""
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="animate-fadeIn space-y-6">
            <h3 className="text-xl font-semibold mb-6">Background & Occupation (पृष्ठभूमि र पेशा)</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm text-gray-400 mb-2">Caste / Ethnicity</label>
                <input 
                  required
                  type="text" 
                  value={formData.casteEthnicity || ''}
                  onChange={e => updateField('casteEthnicity', e.target.value)}
                  placeholder="Brahmin, Chhetri, Newar, etc."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Education</label>
                <input 
                  required
                  type="text" 
                  value={formData.education || ''}
                  onChange={e => updateField('education', e.target.value)}
                  placeholder="Bachelors, Masters, etc."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Occupation</label>
                <input 
                  required
                  type="text" 
                  value={formData.occupation || ''}
                  onChange={e => updateField('occupation', e.target.value)}
                  placeholder="Engineer, Doctor, Student, etc."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Current District</label>
                <input 
                  required
                  type="text" 
                  value={formData.district || ''}
                  onChange={e => updateField('district', e.target.value)}
                  placeholder="Kathmandu, Lalitpur, etc."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="animate-fadeIn space-y-6">
            <h3 className="text-xl font-semibold mb-6">Partner Preferences (जोडी प्राथमिकताहरू)</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm text-gray-400 mb-2">Preferred Age Range</label>
                <input 
                  required
                  type="text" 
                  value={formData.preferredAgeRange || ''}
                  onChange={e => updateField('preferredAgeRange', e.target.value)}
                  placeholder="22-28"
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Preferred Caste</label>
                <input 
                  required
                  type="text" 
                  value={formData.preferredCasteCommunity || 'Any'}
                  onChange={e => updateField('preferredCasteCommunity', e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Preferred Country</label>
                <input 
                  required
                  type="text" 
                  value={formData.preferredCountry || 'Any'}
                  onChange={e => updateField('preferredCountry', e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:border-purple-500 outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm text-gray-400 mb-2">Partner Gender</label>
                <select 
                  className="w-full bg-white/10 border border-white/10 rounded-xl px-4 py-3 outline-none"
                  value={formData.preferredPartnerGender || (formData.gender === 'male' ? 'female' : 'male')}
                  onChange={e => updateField('preferredPartnerGender', e.target.value)}
                >
                  <option value="male" className="bg-[#0f071a]">Male</option>
                  <option value="female" className="bg-[#0f071a]">Female</option>
                </select>
              </div>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="animate-fadeIn text-center space-y-8">
            <div className="w-24 h-24 bg-green-500/20 text-green-500 rounded-full flex items-center justify-center mx-auto text-4xl mb-6">
              ✓
            </div>
            <h3 className="text-2xl font-bold">Verification & Final Steps</h3>
            <p className="text-gray-400 max-w-md mx-auto">
              Please upload a proof of identity to get the <span className="text-green-500 font-bold">Verified Badge</span>. 
              Verified profiles get 5x more matches!
            </p>
            <div className="border-2 border-dashed border-white/20 p-10 rounded-3xl hover:border-purple-500/50 transition-colors cursor-pointer">
              <span className="text-4xl block mb-2">📄</span>
              <p className="text-sm font-medium">Upload Citizenship / Passport Photo</p>
              <p className="text-xs text-gray-500 mt-2">Maximum file size: 5MB</p>
            </div>
            <div className="bg-purple-900/20 p-4 rounded-xl text-left flex items-start gap-4">
              <span className="text-2xl">💳</span>
              <div>
                <h4 className="font-bold text-sm">Setmandu Premium</h4>
                <p className="text-xs text-gray-400">Match Now button is ready. Start your journey with our standard plan.</p>
              </div>
            </div>
          </div>
        )}

        <div className="flex items-center justify-between pt-10">
          {step > 1 && (
            <button 
              type="button"
              onClick={prevStep}
              className="px-8 py-3 rounded-full font-bold text-white/50 hover:text-white transition-colors"
            >
              Back
            </button>
          )}
          <button 
            type="submit"
            className={`px-10 py-3 bg-purple-600 hover:bg-purple-500 rounded-full font-bold transition-all transform hover:scale-105 ml-auto shadow-lg shadow-purple-500/20 ${step === 4 ? 'bg-green-600 hover:bg-green-500' : ''}`}
          >
            {step === 4 ? 'Finish & Match Now 💖' : 'Next Step'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default RegistrationForm;

import React, { useState, useEffect } from 'react';
import { UserProfile, MatchResult } from '../types';
import ProfileCard from './ProfileCard';
import Confetti from './Confetti';

interface MatchingEngineProps {
  currentUser: UserProfile;
}

// Simulated Match Scoring Algorithm as per requirements
const calculateMatchScore = (currentUser: UserProfile, candidateUser: UserProfile): number => {
  let score = 0;

  // Gender match (mandatory - opposite gender only for traditional matrimonial)
  if (candidateUser.gender !== currentUser.preferredPartnerGender) return 0;

  // Age match
  const [minAge, maxAge] = currentUser.preferredAgeRange.split('-').map(Number);
  if (candidateUser.age >= minAge && candidateUser.age <= maxAge) score += 30;

  // Caste match
  if (currentUser.preferredCasteCommunity === 'Any' ||
      candidateUser.casteEthnicity === currentUser.preferredCasteCommunity) score += 25;

  // Country match
  if (currentUser.preferredCountry === 'Any' ||
      candidateUser.countryResidence === currentUser.preferredCountry) score += 20;

  // Occupation/Education bonus
  if (candidateUser.occupation) score += 15;
  if (candidateUser.education) score += 10;

  return score;
};

// Simulated mock database of users
const generateMockUsers = (count: number): UserProfile[] => {
  const castes = ['Brahmin', 'Chhetri', 'Newar', 'Gurung', 'Rai', 'Magar', 'Tamang'];
  const occupations = ['Software Engineer', 'Doctor', 'Nurse', 'Banker', 'Business Owner', 'Civil Servant', 'Teacher'];
  const districts = ['Kathmandu', 'Lalitpur', 'Bhaktapur', 'Pokhara', 'Chitwan', 'Butwal'];

  return Array.from({ length: count }).map((_, i) => {
    const gender = Math.random() > 0.5 ? 'male' : 'female';
    const fullName = gender === 'male' 
      ? `Aayush ${['Sharma', 'Thapa', 'Poudel', 'Adhikari'][Math.floor(Math.random() * 4)]}`
      : `Priya ${['Maharjan', 'Gurung', 'Basnet', 'Shrestha'][Math.floor(Math.random() * 4)]}`;

    return {
      uid: `user-${i}`,
      fullName,
      gender: gender as any,
      age: 22 + Math.floor(Math.random() * 15),
      casteEthnicity: castes[Math.floor(Math.random() * castes.length)],
      district: districts[Math.floor(Math.random() * districts.length)],
      countryResidence: Math.random() > 0.8 ? 'USA' : 'Nepal',
      occupation: occupations[Math.floor(Math.random() * occupations.length)],
      education: 'Master\'s Degree',
      height: "5'" + (Math.floor(Math.random() * 8) + 2) + "\"",
      recentPhotoURL: `https://picsum.photos/seed/${i + 200}/400/500`,
      preferredPartnerGender: gender === 'male' ? 'female' : 'male',
      preferredAgeRange: '20-30',
      preferredCasteCommunity: 'Any',
      preferredCountry: 'Any',
      isVerified: Math.random() > 0.3,
      registrationDate: new Date().toISOString(),
      bio: "Looking for someone who values family and has a good sense of humor."
    };
  });
};

const MatchingEngine: React.FC<MatchingEngineProps> = ({ currentUser }) => {
  const [matches, setMatches] = useState<MatchResult[]>([]);
  const [loading, setLoading] = useState(true);
  const [showConfetti, setShowConfetti] = useState(false);

  useEffect(() => {
    // Simulate API fetch & calculation
    const timer = setTimeout(() => {
      const allUsers = generateMockUsers(50);
      const calculatedMatches: MatchResult[] = allUsers
        .map(user => ({
          ...user,
          score: calculateMatchScore(currentUser, user)
        }))
        .filter(match => match.score > 0)
        .sort((a, b) => b.score - a.score);

      setMatches(calculatedMatches);
      setLoading(false);
      setShowConfetti(true);
    }, 2500);

    return () => clearTimeout(timer);
  }, [currentUser]);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
        <div className="relative w-24 h-24 mb-8">
            <div className="absolute inset-0 border-4 border-purple-500/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-purple-500 rounded-full border-t-transparent animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-3xl">❤️</div>
        </div>
        <h2 className="text-2xl font-bold mb-2 rose-gold-text animate-pulse">Scanning the Stars...</h2>
        <p className="text-gray-400">Finding the most compatible partners for you in Nepal.</p>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-12 w-full max-w-4xl">
            {[1,2,3].map(i => (
                <div key={i} className="glass h-96 rounded-3xl shimmer"></div>
            ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12">
      {showConfetti && <Confetti />}
      <div className="text-center">
        <h2 className="text-4xl font-bold mb-4 rose-gold-text">Found {matches.length} Matches ✨</h2>
        <p className="text-gray-400">Based on your preferences and profile details.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {matches.map((match, index) => (
          <div key={match.uid} className="animate-fadeIn" style={{ animationDelay: `${index * 100}ms` }}>
            <ProfileCard match={match} />
          </div>
        ))}
      </div>

      {matches.length === 0 && (
        <div className="text-center py-20 glass rounded-3xl">
          <p className="text-xl text-gray-400">No matches found right now. Try expanding your preferences.</p>
        </div>
      )}
    </div>
  );
};

export default MatchingEngine;

import React from 'react';

const BackgroundHearts: React.FC = () => {
  return (
    <div className="fixed inset-0 pointer-events-none overflow-hidden z-0">
      {[...Array(20)].map((_, i) => (
        <div 
          key={i}
          className="heart-particle"
          style={{
