      let current = 0;
      const step = target / 100;
      const interval = setInterval(() => {
        current += step;
        if (current >= target) {
          setter(target);
          clearInterval(interval);
        } else {
          setter(Math.floor(current));
        }
      }, 20);
    };

    increment(12540, setUsers);
    increment(8420, setMatches);
    increment(1520, setSuccess);
  }, []);

  return (
