          setCurrentUser(null);
          setAppState(AppState.HOME);
        }}
      />

      <main className="relative z-10 pt-20">
        {appState === AppState.HOME && (
          <>
            <Hero onStart={() => setAppState(AppState.REGISTER)} />
            <Stats />
            <div className="max-w-6xl mx-auto px-6 py-20 text-center">
              <h2 className="text-3xl md:text-4xl font-bold mb-12 rose-gold-text">How It Works (कसरी काम गर्छ)</h2>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <StepCard 
                  icon="📝" 
                  title="Create Profile" 
                  desc="Tell us about yourself and upload citizenship for verification." 
                />
                <StepCard 
                  icon="💳" 
                  title="Pay & Verify" 
                  desc="Secure your profile with a one-time fee of Rs. 2000." 
                />
                <StepCard 
                  icon="💍" 
                  title="Find Match" 
                  desc="Start conversations with verified Nepali profiles." 
                />
              </div>
            </div>
          </>
        )}

        {appState === AppState.LOGIN && (
          <div className="max-w-md mx-auto px-6 py-20">
            <LoginForm onComplete={handleAuthComplete} />
          </div>
        )}

        {appState === AppState.REGISTER && (
          <div className="max-w-4xl mx-auto px-6 py-10">
            <RegistrationForm onComplete={handleAuthComplete} />
          </div>
        )}

        {appState === AppState.MATCHING && currentUser && (
          <div className="max-w-6xl mx-auto px-6 py-10">
            <MatchingEngine currentUser={currentUser} />
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
};

