import React, { useState, useEffect } from 'react';
import { UserProfile, MatchResult } from '../types';
import ProfileCard from './ProfileCard';
import Confetti from './Confetti';

interface MatchingEngineProps {
  currentUser: UserProfile;
}

const calculateMatchScore = (currentUser: UserProfile, candidateUser: UserProfile): number => {
  let score = 0;
  if (candidateUser.gender !== currentUser.preferredPartnerGender) return 0;

  // Age match (30 points)
  const [minAge, maxAge] = currentUser.preferredAgeRange.split('-').map(Number);
  if (candidateUser.age >= minAge && candidateUser.age <= maxAge) {
    score += 30;
  } else if (Math.abs(candidateUser.age - currentUser.age) <= 5) {
    score += 15;
  }

  // Caste match (25 points)
  if (currentUser.preferredCasteCommunity === 'Any' ||
      candidateUser.casteEthnicity.toLowerCase() === currentUser.preferredCasteCommunity.toLowerCase()) {
    score += 25;
  }

  // Country match (20 points)
  if (currentUser.preferredCountry === 'Any' ||
      candidateUser.countryResidence.toLowerCase() === currentUser.preferredCountry.toLowerCase()) {
    score += 20;
  }

  // Occupation/Education bonus (15 + 10 points)
  if (candidateUser.occupation) score += 15;
  if (candidateUser.education) score += 10;

  return Math.min(score, 100);
};

const generateMatches = (currentUser: UserProfile, count: number): MatchResult[] => {
  const castes = ['Brahmin', 'Chhetri', 'Newar', 'Gurung', 'Rai', 'Magar', 'Tamang', 'Lama', 'Sherpa'];
  const occupations = ['Doctor', 'Nurse', 'Engineer', 'Banker', 'Civil Servant', 'IT Professional', 'Teacher', 'Business'];
  const districts = ['Kathmandu', 'Pokhara', 'Lalitpur', 'Bhaktapur', 'Dharan', 'Butwal', 'Chitwan'];

  const results: MatchResult[] = [];
  for (let i = 0; i < count; i++) {
    const isMale = currentUser.preferredPartnerGender === 'male';
    const firstNames = isMale ? ['Aayush', 'Bijay', 'Sandesh', 'Prabin', 'Sudip', 'Anish'] : ['Priya', 'Sita', 'Anita', 'Bhawana', 'Sunita', 'Karishma'];
    const lastNames = ['Sharma', 'Thapa', 'Poudel', 'Adhikari', 'Maharjan', 'Basnet', 'Shrestha', 'Karki'];

    // Create candidate profile with all required UserProfile fields
    const candidate: UserProfile = {
      uid: `match-${i}`,
      fullName: `${firstNames[Math.floor(Math.random() * firstNames.length)]} ${lastNames[Math.floor(Math.random() * lastNames.length)]}`,
      gender: currentUser.preferredPartnerGender,
      age: Math.max(18, currentUser.age - 3 + Math.floor(Math.random() * 8)),
      casteEthnicity: castes[Math.floor(Math.random() * castes.length)],
      district: districts[Math.floor(Math.random() * districts.length)],
      countryResidence: Math.random() > 0.85 ? 'Australia' : 'Nepal',
      occupation: occupations[Math.floor(Math.random() * occupations.length)],
      education: 'Master\'s Degree',
      height: (5 + Math.floor(Math.random() * 2)) + "'" + Math.floor(Math.random() * 12) + "\"",
      recentPhotoURL: `https://i.pravatar.cc/500?u=match${i}`,
      // Fix: Adding missing isPaid property to satisfy UserProfile interface
      isPaid: true,
      preferredPartnerGender: currentUser.gender,
      preferredAgeRange: '20-30',
      preferredCasteCommunity: 'Any',
      preferredCountry: 'Any',
      isVerified: Math.random() > 0.3,
      registrationDate: new Date().toISOString(),
      bio: "Living life to the fullest. Family-oriented and looking for a meaningful connection."
    };

    const score = calculateMatchScore(currentUser, candidate);
    if (score >= 50) {
      results.push({ ...candidate, score });
    }
  }
  return results.sort((a, b) => b.score - a.score);
};

const MatchingEngine: React.FC<MatchingEngineProps> = ({ currentUser }) => {
  const [matches, setMatches] = useState<MatchResult[]>([]);
  const [loading, setLoading] = useState(true);
  const [showConfetti, setShowConfetti] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => {
      const results = generateMatches(currentUser, 40);
      setMatches(results);
      setLoading(false);
      setShowConfetti(true);
    }, 3000);
    return () => clearTimeout(timer);
  }, [currentUser]);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[70vh] text-center px-4">
        <div className="relative mb-12">
            <div className="w-32 h-32 border-4 border-purple-600/10 rounded-full animate-pulse"></div>
            <div className="absolute inset-0 w-32 h-32 border-t-4 border-purple-500 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center text-4xl">🧿</div>
        </div>
        <h2 className="text-3xl font-extrabold mb-4 rose-gold-text">Searching the Universe...</h2>
        <p className="text-gray-400 max-w-sm mx-auto leading-relaxed">
            Our AI is matching your soul with thousands of profiles across Nepal and abroad.
        </p>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mt-16 w-full opacity-30">
            {[1,2,3].map(i => <div key={i} className="glass h-96 rounded-3xl shimmer"></div>)}
        </div>
      </div>
    );
  }

  return (
    <div className="animate-fadeIn">
      {showConfetti && <Confetti />}
      <div className="flex flex-col md:flex-row items-center justify-between mb-12 gap-6">
        <div>
          <h2 className="text-4xl font-extrabold rose-gold-text">Destiny Found ✨</h2>
          <p className="text-gray-400 mt-1">We found {matches.length} matches tailored for you, {currentUser.fullName.split(' ')[0]}.</p>
        </div>
        <div className="flex gap-3">
            <button className="px-5 py-2 glass rounded-full text-xs font-bold uppercase tracking-wider hover:bg-white/10">Filters</button>
            <button className="px-5 py-2 glass rounded-full text-xs font-bold uppercase tracking-wider hover:bg-white/10">Sort: Score</button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
        {matches.map((match, index) => (
          <div key={match.uid} className="animate-slideUp" style={{ animationDelay: `${index * 150}ms` }}>
            <ProfileCard match={match} />
          </div>
        ))}
      </div>

      {matches.length === 0 && (
        <div className="text-center py-32 glass rounded-3xl">
          <span className="text-6xl block mb-6">🏜️</span>
          <h3 className="text-2xl font-bold mb-2">No Matches Found</h3>
          <p className="text-gray-500 max-w-md mx-auto px-6">Try relaxing your preferences (age range or caste) to see more potential partners.</p>
          <button className="mt-8 px-8 py-3 bg-purple-600 rounded-full font-bold">Adjust Preferences</button>
        </div>
      )}
    </div>
  );
};

export default MatchingEngine;
